#[test]
fn test_registry_lock() uses (evm: mut Evm) {
    let admin = evm.address()
    let registry = evm.create2<BountyRegistry>(value: 0, args: (admin, 0), salt: 50)
    let challenge = Address { inner: 12345 }

    // Register challenge first (required for locking)
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::RegisterChallenge { challenge, prize_amount: 0 })

    // Initially not locked
    let locked: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge })
    assert(!locked)

    // Lock
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge })

    // Now locked
    let locked: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge })
    assert(locked)
}

