fn test_registry_multiple_simultaneous_locks() uses (evm: mut Evm) {
    let admin = evm.address()
    let registry = evm.create2<BountyRegistry>(value: 0, args: (admin, 0), salt: 89)

    let game1 = evm.create2<DummyGame>(value: 0, args: (true,), salt: 90)
    let game2 = evm.create2<DummyGame>(value: 0, args: (true,), salt: 91)

    // Register both
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::RegisterChallenge { challenge: game1, prize_amount: 0 })
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::RegisterChallenge { challenge: game2, prize_amount: 0 })

    // Lock both
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge: game1 })
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge: game2 })

    // Both should be locked
    let locked1: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge: game1 })
    assert(locked1)
    let locked2: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge: game2 })
    assert(locked2)

    // Claim both
    evm.call(addr: registry, gas: 500000, value: 0, message: RegistryMsg::Claim { challenge: game1 })
    evm.call(addr: registry, gas: 500000, value: 0, message: RegistryMsg::Claim { challenge: game2 })

    // Both closed
    let open1: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsOpenChallenge { challenge: game1 })
    assert(!open1)
    let open2: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsOpenChallenge { challenge: game2 })
    assert(!open2)
}

// Note: Funding tests (deploy with value, Fund message with value) require
// the test EVM to have ETH balance, which is not available in the Fe test
// context. These are covered by Forge tests in test/BountyRegistry.t.sol.

/// Manages time-locked claims on challenges.
/// Each lock maps a challenge address to a `Lock` (claimer + expiry block).
struct LockStore {
    locks: StorageMap<Address, Lock>,
    latest_lock_expiry: u256,
}

/// Top-level registry storage: admin config, challenges, and lock management.
struct RegistryStore {
    lock_store: LockStore,
    admin: Address,
    lock_deposit: u256,
    challenges: StorageMap<Address, Challenge>,
}

pub contract BountyRegistry uses (ctx: Ctx, call: mut Call) {
    mut store: RegistryStore

    #[payable]
    init(admin: Address, lock_deposit: u256) uses (mut store) {
        store.admin = admin
        store.lock_deposit = lock_deposit
    }

    recv RegistryMsg {
        #[payable]
        Lock { challenge } uses (mut store, ctx) {
            store.lock(challenge).unwrap()
        }

        IsLocked { challenge } -> bool uses (store, ctx) {
            store.lock_store.is_locked(challenge)
        }

        RegisterChallenge { challenge, prize_amount } uses (mut store, ctx) {
            store.register_challenge(challenge, prize_amount).unwrap()
        }

        RemoveChallenge { challenge } uses (mut store, ctx) {
            store.remove_challenge(challenge).unwrap()
        }

        IsOpenChallenge { challenge } -> bool uses (store) {
            store.challenges.get(key: challenge).is_open
        }

        Claim { challenge } uses (mut store, ctx, mut call) {
            store.claim(challenge).unwrap()
        }

        ValidateOwnsLock { owner, challenge } uses (store, ctx) {
            store.validate_owns_lock(challenge, owner).unwrap()
        }

        #[payable]
        Fund {}

        Withdraw uses (store, ctx, mut call) {
            store.withdraw().unwrap()
        }

        GetPrizeAmount { challenge } -> u128 uses (store) {
            store.challenges.get(key: challenge).prize_amount
        }

        GetLockInfo { challenge } -> (Address, u256) uses (store, ctx) {
            let lock = store.lock_store.locks.get(key: challenge)
            (lock.claimer, lock.valid_until_block)
        }

        GetLockDeposit -> u256 uses (store) {
            store.lock_deposit
        }

        GetBalance -> u256 uses (ctx) {
            ctx.selfbalance()
        }
    }
}

