    0 + 2 * 1000 + 5 * 1000000 + 666 * 1000000000,             // 1:  neighbors 0, 2, 5
    1 + 3 * 1000 + 6 * 1000000 + 666 * 1000000000,             // 2:  neighbors 1, 3, 6
    2 + 7 * 1000 + 666 * 1000000 + 666 * 1000000000,           // 3:  neighbors 2, 7
    0 + 5 * 1000 + 8 * 1000000 + 666 * 1000000000,             // 4:  neighbors 0, 5, 8
    1 + 4 * 1000 + 6 * 1000000 + 9 * 1000000000,               // 5:  neighbors 1, 4, 6, 9
    2 + 5 * 1000 + 7 * 1000000 + 10 * 1000000000,              // 6:  neighbors 2, 5, 7, 10
    3 + 6 * 1000 + 11 * 1000000 + 666 * 1000000000,            // 7:  neighbors 3, 6, 11
    4 + 9 * 1000 + 12 * 1000000 + 666 * 1000000000,            // 8:  neighbors 4, 9, 12
    5 + 8 * 1000 + 10 * 1000000 + 13 * 1000000000,             // 9:  neighbors 5, 8, 10, 13
    6 + 9 * 1000 + 11 * 1000000 + 14 * 1000000000,             // 10: neighbors 6, 9, 11, 14
    7 + 10 * 1000 + 15 * 1000000 + 666 * 1000000000,           // 11: neighbors 7, 10, 15
    8 + 13 * 1000 + 666 * 1000000 + 666 * 1000000000,          // 12: neighbors 8, 13
    9 + 12 * 1000 + 14 * 1000000 + 666 * 1000000000,           // 13: neighbors 9, 12, 14
    10 + 13 * 1000 + 15 * 1000000 + 666 * 1000000000,          // 14: neighbors 10, 13, 15
    11 + 14 * 1000 + 666 * 1000000 + 666 * 1000000000,         // 15: neighbors 11, 14
]

pub fn encode_moves(m0: u256, m1: u256, m2: u256, m3: u256) -> u256 {
    m0 + m1 * 1000 + m2 * 1000000 + m3 * 1000000000
}

pub fn decode_move(encoded: u256, slot: u256) -> u256 {
    if slot == 0 { return encoded % 1000 }
    if slot == 1 { return (encoded / 1000) % 1000 }
    if slot == 2 { return (encoded / 1000000) % 1000 }
