pub struct Challenge {
    pub is_open: bool,
    pub prize_amount: u128,
}

pub struct Lock {
    pub claimer: Address,
    pub valid_until_block: u256,
}

pub fn winning_value(index: u256) -> u256 {
    if index == 15 { return 0 }
    return index + 1
}

/// Unpacks a packed board into a 16-element array.
pub fn unpack_board(packed: u256) -> [u256; 16] {
    let mut board: [u256; 16] = [0; 16]
    let mut i: usize = 0
    while i < 16 {
        board[i] = (packed >> ((i as u256) * 4)) & 0xF
        i += 1
    }
    return board
}

/// Packs a 16-element array into a single u256.
pub fn pack_board(board: [u256; 16]) -> u256 {
    let mut packed: u256 = 0
    let mut i: usize = 0
    while i < 16 {
        packed = packed | (board[i] << ((i as u256) * 4))
        i += 1
    }
    return packed
}

