// =============================================================================
// Game contract — 15-puzzle challenge with flat board in StorageMap
// =============================================================================

use std::abi::sol
use std::evm::{Address, Ctx, Call, StorageMap, Evm, assert, revert}
use shared::{
    Error,
    winning_value,
    unpack_board,
    LockValidatorMsg,
}
use shared::game_util::{ADJACENCY, is_movable_to}
use shared::dummy_lock_validator::DummyLockValidator
use shared::{SOLVED_BOARD, UNSOLVABLE_BOARD, ONE_MOVE_BOARD}

pub msg GameMsg {
    #[selector = sol("getBoard(uint256)")]
    GetBoard { index: u256 } -> u256,
    #[selector = sol("isSolved()")]
    IsSolved -> bool,
    #[selector = sol("moveField(uint256)")]
    MoveField { index: u256 },
}

struct GameStore {
    lock_validator: Address,
    board: StorageMap<u256, u256>,
}

pub contract Game uses (ctx: Ctx, call: mut Call) {
    mut store: GameStore

    init(lock_validator: Address, packed_board: u256) uses (mut store) {
        store.lock_validator = lock_validator
        let board = unpack_board(packed: packed_board)
        let mut i: u256 = 0
        while i < 16 {
            store.board.set(key: i, value: board[i as usize])
            i += 1
        }
    }

    recv GameMsg {
        GetBoard { index } -> u256 uses (store) {
            store.board.get(key: index)
        }

        IsSolved -> bool uses (store) {
            let mut i: u256 = 0
            while i < 16 {
                if store.board.get(key: i) != winning_value(index: i) {
                    return false
                }
                i += 1
            }
            return true
        }

        MoveField { index } uses (mut store, ctx, mut call) {
            store.lock_validator.call(LockValidatorMsg::ValidateOwnsLock { owner: ctx.caller(), challenge: ctx.address() })

            if index > 15 {
                revert(Error::InvalidIndex)
            }

            let mut empty_idx: u256 = 16
            let mut j: u256 = 0
            while j < 16 {
                if store.board.get(key: j) == 0 {
                    empty_idx = j
                }
                j += 1
            }

            let encoded = ADJACENCY[empty_idx as usize]
            if !is_movable_to(encoded_moves: encoded, target: index) {
                revert(Error::NotMovable)
            }

            let val = store.board.get(key: index)
            store.board.set(key: index, value: 0)
            store.board.set(key: empty_idx, value: val)
        }
    }
}

