```fe
// =============================================================================
// GameEnum — 15-puzzle using enums, match, struct with impl, fixed array
//
// Board stored as [u256; 16] fixed array. Move logic uses an enum Direction
// and match expressions. Point struct with impl methods converts between
// flat index and (row, col) coordinates.
//
// Fe features exercised: enum, match expression, struct with impl,
// method calls, [u256; 16] fixed array in storage.
// =============================================================================

use std::abi::sol
use std::evm::{Address, Ctx, Call, Evm, assert, revert}
use shared::{
    Error,
    winning_value,
    unpack_board,
    SOLVED_BOARD,
    UNSOLVABLE_BOARD,
    ONE_MOVE_BOARD,
    LockValidatorMsg,
}
use shared::dummy_lock_validator::DummyLockValidator

enum Direction {
    Up,
    Down,
    Left,
    Right,
}

struct Point {
    row: usize,
    col: usize,
}

impl Point {
    fn from_index(index: usize) -> Point {
        Point { row: index / 4, col: index % 4 }
    }

    fn to_index(self) -> usize {
        self.row * 4 + self.col
    }

    fn can_move(self, dir: Direction) -> bool {
        match dir {
            Direction::Up => self.row > 0,
            Direction::Down => self.row < 3,
            Direction::Left => self.col > 0,
            Direction::Right => self.col < 3,
        }
    }

    fn neighbor(self, dir: Direction) -> Point {
        match dir {
            Direction::Up => Point { row: self.row - 1, col: self.col },
            Direction::Down => Point { row: self.row + 1, col: self.col },
            Direction::Left => Point { row: self.row, col: self.col - 1 },
            Direction::Right => Point { row: self.row, col: self.col + 1 },
        }
    }
}

fn winning_value_enum(index: usize) -> u256 {
    winning_value(index: index as u256)
}

pub msg GameEnumMsg {
    #[selector = sol("getBoard(uint256)")]
    GetBoard { index: u256 } -> u256,
    #[selector = sol("isSolved()")]
    IsSolved -> bool,
    #[selector = sol("moveField(uint256)")]
    MoveField { index: u256 },
}

struct GameEnumStore {
    lock_validator: Address,
    board: [u256; 16],
}

pub contract GameEnum uses (ctx: Ctx, call: mut Call) {
    mut store: GameEnumStore

    init(lock_validator: Address, packed_board: u256) uses (mut store) {
        store.lock_validator = lock_validator
        let board = unpack_board(packed: packed_board)
        let mut i: usize = 0
        while i < 16 {
            store.board[i] = board[i]
            i += 1
        }
    }

    recv GameEnumMsg {
        GetBoard { index } -> u256 uses (store) {
            store.board[index as usize]
        }

        IsSolved -> bool uses (store) {
            let mut i: usize = 0
            while i < 16 {
                if store.board[i] != winning_value_enum(index: i) {
                    return false
                }
                i += 1
            }
            return true
        }

        MoveField { index } uses (mut store, ctx, mut call) {
            store.lock_validator.call(LockValidatorMsg::ValidateOwnsLock { owner: ctx.caller(), challenge: ctx.address() })

            if index > 15 {
                revert(Error::InvalidIndex)
            }

            let idx = index as usize

            let mut empty_idx: usize = 16
            let mut j: usize = 0
            while j < 16 {
                if store.board[j] == 0 {
                    empty_idx = j
                }
                j += 1
            }

            let empty_pt = Point::from_index(index: empty_idx)
            let mut can_swap: bool = false

            if empty_pt.can_move(dir: Direction::Up) {
                let nb = empty_pt.neighbor(dir: Direction::Up)
                if nb.to_index() == idx {
                    can_swap = true
                }
            }
            if empty_pt.can_move(dir: Direction::Down) {
                let nb = empty_pt.neighbor(dir: Direction::Down)
                if nb.to_index() == idx {
                    can_swap = true
                }
            }
            if empty_pt.can_move(dir: Direction::Left) {
                let nb = empty_pt.neighbor(dir: Direction::Left)
                if nb.to_index() == idx {
                    can_swap = true
                }
            }
            if empty_pt.can_move(dir: Direction::Right) {
                let nb = empty_pt.neighbor(dir: Direction::Right)
                if nb.to_index() == idx {
                    can_swap = true
                }
            }

            if !can_swap {
                revert(Error::NotMovable)
            }

            let val = store.board[idx]
            store.board[idx] = 0
            store.board[empty_idx] = val
        }
    }
}

