    let game = evm.create2<DummyGame>(value: 0, args: (true,), salt: 86)

    evm.call(
        addr: registry, gas: 100000, value: 0,
        message: RegistryMsg::RegisterChallenge { challenge: game, prize_amount: 0 }
    )
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge: game })
    evm.call(
        addr: registry, gas: 500000, value: 0,
        message: RegistryMsg::Claim { challenge: game }
    )

    // Second claim should revert (challenge closed)
    evm.call(
