#[test]
fn test_registry_multiple_simultaneous_locks() uses (evm: mut Evm) {
    let admin = evm.address()
    let registry = evm.create2<BountyRegistry>(value: 0, args: (admin, 0), salt: 89)

    let game1 = evm.create2<DummyGame>(value: 0, args: (true,), salt: 90)
    let game2 = evm.create2<DummyGame>(value: 0, args: (true,), salt: 91)

    // Register both
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::RegisterChallenge { challenge: game1, prize_amount: 0 })
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::RegisterChallenge { challenge: game2, prize_amount: 0 })

    // Lock both
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge: game1 })
    evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::Lock { challenge: game2 })

    // Both should be locked
    let locked1: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge: game1 })
    assert(locked1)
    let locked2: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsLocked { challenge: game2 })
    assert(locked2)

    // Claim both
    evm.call(addr: registry, gas: 500000, value: 0, message: RegistryMsg::Claim { challenge: game1 })
    evm.call(addr: registry, gas: 500000, value: 0, message: RegistryMsg::Claim { challenge: game2 })

    // Both closed
    let open1: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsOpenChallenge { challenge: game1 })
    assert(!open1)
    let open2: bool = evm.call(addr: registry, gas: 100000, value: 0, message: RegistryMsg::IsOpenChallenge { challenge: game2 })
    assert(!open2)
}

